import Faqv2 from "@components/common/faq-v2";
import React from "react";

const faq = (faqData) => {
  // console.log("faq", faqData);

  const data =
    faqData?.faq
      ?.filter((item) => item.status)
      ?.map((item) => ({
        question: item.question,
        answer: item.answer,
      })) || [];

  if (data.length === 0) return null;
  return (
    <section className="faq-section">
      <div className="hero-wrapper bg-black-faq">
        <Faqv2 faqData={data} />
      </div>
    </section>
  );
};

export default faq;
